import{_ as a,o as e,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const F=JSON.parse('{"title":"F01: 營收因子與定價權分析 - 財務分析專家審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260424/F01_營收因子與定價權分析.md","filePath":"審計報告庫/財務審計/6261_久元/20260424/F01_營收因子與定價權分析.md"}'),l={name:"審計報告庫/財務審計/6261_久元/20260424/F01_營收因子與定價權分析.md"};function i(n,t,d,s,h,c){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="f01-營收因子與定價權分析-財務分析專家審計報告" tabindex="-1">F01: 營收因子與定價權分析 - 財務分析專家審計報告 <a class="header-anchor" href="#f01-營收因子與定價權分析-財務分析專家審計報告" aria-label="Permalink to &quot;F01: 營收因子與定價權分析 - 財務分析專家審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>營收成長或衰退的實質因子分析：是由於「銷量增加 (Volume Up)」還是「單價調整 (Price Up)？」透過拆解 P（價格）與 V（銷量），判定公司業績成長的真實驅動力。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>根據截至2025年Q4最新公開數據，久元（6261）FY25全年營收315.17億元，年增4.0%，成長動能由FY24的+15.8%顯著放緩。毛利率從FY24平均30.6%回升至FY25的29.8%，顯示營收成長主要來自「銷量擴張」而非「單價提升」。自有設備銷售比重由36%提升至39%，產品組合優化正在緩衝價格競爭壓力，但整體仍處於「量增價平」的紅海追隨階段。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>評級：A-（良，略偏持平）</strong></p><p>FY23→FY24營收年增+15.8%（261.70→303.11億元），FY24→FY25年增+4.0%（303.11→315.17億元），成長動能明顯放緩。毛利率方面，FY24平均30.6%（Q1: 29.5%, Q2: 35.0%, Q3: 29.5%, Q4: 25.5%），FY25平均29.8%（Q1: 25.3%, Q2: 30.3%, Q3: 33.2%, Q4: 30.6%）。FY25Q4單季毛利率30.6%，較Q1的25.3%回升5.3個百分點，顯示下半年產品組合改善。YoY營收成長：24Q2 +31.4%、24Q3 +16.9%，但24Q4轉負-21.2%；25Q3 +9.9%、25Q4 +27.8%，呈現V型復甦。關鍵警訊：FY25全年營收僅微增4%，顯示半導體測試代工市場的價格競爭加劇，公司定價權有限。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、營收成長動能拆解-fy對比" tabindex="-1">一、營收成長動能拆解（FY對比） <a class="header-anchor" href="#一、營收成長動能拆解-fy對比" aria-label="Permalink to &quot;一、營收成長動能拆解（FY對比）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年度</th><th>合併營收(億元)</th><th>年增率</th><th>毛利率</th><th>營業利益(億元)</th></tr></thead><tbody><tr><td>FY23 (112年)</td><td>261.70</td><td>—</td><td>29.5%</td><td>8.34</td></tr><tr><td>FY24 (113年)</td><td>303.11</td><td>+15.8%</td><td>30.6%</td><td>28.14</td></tr><tr><td>FY25 (114年)</td><td>315.17</td><td>+4.0%</td><td>29.8%</td><td>10.89</td></tr></tbody></table><p>FY24的+15.8%成長主要來自Q2（+31.4% YoY）的爆發，該季營收達114.10億元、毛利率35.0%，為四年來最高。但FY24Q4營收轉負（-21.2% YoY），顯示下半年需求放緩。FY25則呈現V型走勢：Q1-Q2承壓（-16.2% YoY），Q3-Q4強勁反彈（+9.9%、+27.8% YoY），全年營收315.17億元僅微增4.0%。</p><h3 id="二、定價權評估-量增價平-vs-價量齊揚" tabindex="-1">二、定價權評估：量增價平 vs 價量齊揚 <a class="header-anchor" href="#二、定價權評估-量增價平-vs-價量齊揚" aria-label="Permalink to &quot;二、定價權評估：量增價平 vs 價量齊揚&quot;">​</a></h3><p>從毛利率與營收的連動關係判斷：</p><ul><li>FY24Q2營收114.10億元、毛利率35.0%：此為「量價齊揚」的黃金窗口，可能來自半導體測試需求爆發加上自有設備銷售比重提升。</li><li>FY24Q3→Q4毛利率從35.0%急降至29.5%→25.5%，營收也從114.10億降至96.31億→92.56億元：顯示Q4面臨「降價衝量」壓力，但衝量效果有限（營收仍下滑3.9% QoQ）。</li><li>FY25毛利率在Q1觸底25.3%後逐季回升至Q4的30.6%，但全年營收僅增4%：確認公司正在透過「產品組合優化」（自有設備比重36%→39%）來改善毛利，而非單純靠漲價。</li></ul><h3 id="三、產品組合變化對定價權的影響" tabindex="-1">三、產品組合變化對定價權的影響 <a class="header-anchor" href="#三、產品組合變化對定價權的影響" aria-label="Permalink to &quot;三、產品組合變化對定價權的影響&quot;">​</a></h3><p>根據富果法說會摘要，久元四大業務領域為半導體、RFID、光電及Mini LED。其中自有設備銷售比重由2024年的36%提升至2025上半年的39%，這是關鍵的定價權改善訊號。自有設備相較於測試代工服務具有更高的毛利空間和客戶黏著度，代表公司正從「勞力密集型測試代工」向「技術密集型設備銷售」轉型。</p><h3 id="四、未來路徑預測" tabindex="-1">四、未來路徑預測 <a class="header-anchor" href="#四、未來路徑預測" aria-label="Permalink to &quot;四、未來路徑預測&quot;">​</a></h3><p>2025下半年管理層預期營運略優於上半年，並透過新成立的美國子公司拓展產品線與客戶群。2025Q4單季營收118.28億元創近兩季新高，年增+27.8%。但需警惕：</p><ol><li>營收成長仍高度依賴季節性旺季（Q4通常為全年最高）</li><li>毛利率回升幅度有限（30.6% vs 高峰35.0%），顯示定價權尚未完全恢復</li><li>若中國大陸半導體設備廠價格戰持續，久元的代工業務可能面臨進一步壓縮</li></ol><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>久元的營收成長模式正在經歷關鍵轉型期。過去（FY24）的爆發性成長來自半導體測試代工需求的周期性高峰，但這種「衝量型成長」在FY25已顯現疲態——全年僅增4%。</p><p><strong>核心診斷：</strong> 久元目前處於「定價權重建期」。自有設備銷售比重提升至39%是正面訊號，代表公司正從低毛利的測試代工（勞力密集）轉向高毛利的設備銷售（技術密集）。然而，這種轉型需要時間驗證——FY25全年毛利率僅29.8%，仍低於FY24的30.6%。</p><p><strong>風險評估：</strong> 若自有設備銷售比重無法持續提升，久元將陷入「半導體測試代工紅海競爭」。中國大陸設備廠的內捲式價格戰（據新聞報導「中國半導體設備廠營收創新高但利潤縮水」）可能持續壓縮久元的代工毛利空間。</p><p><strong>投資價值判斷：</strong> 久元目前不具備強大的品牌溢價能力，其營收成長主要來自「銷量擴張」而非「單價提升」。投資者應密切追蹤自有設備銷售比重的變化趨勢——若該指標能穩定超過45%，則定價權改善的論述將獲得實質支撐。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>數據採集器查詢</strong>: <code>python3 /Users/kaipro/.openclaw/skills/finmind/數據採集器.py finance 6261 2023-04-01 2026-04-24 --df</code>（科目：營業收入、營業毛利、營業利益）</li><li><strong>數據採集器查詢</strong>: <code>python3 /Users/kaipro/.openclaw/skills/finmind/數據採集器.py revenue 6261 2023-04-01 2026-04-24 --df</code>（科目：月營收）</li><li><strong>富果法說會摘要</strong>: <a href="https://blog.fugle.tw/post/earnings-call-6261-2025-08-28%EF%BC%88%E8%87%AA%E6%9C%89%E8%A8%AD%E5%82%99%E9%8A%B7%E5%94%AE%E6%AF%94%E9%87%8D36%25%E2%86%9239%25%EF%BC%8C%E5%9B%9B%E5%A4%A7%E6%A5%AD%E5%8B%99%E9%A0%98%E5%9F%9F%EF%BC%89" target="_blank" rel="noreferrer">https://blog.fugle.tw/post/earnings-call-6261-2025-08-28（自有設備銷售比重36%→39%，四大業務領域）</a></li><li><strong>CMoney財報公告</strong>: <a href="https://cmnews.com.tw/article/cmoneyaicurator-310e19db-22b4-11f1-bf01-df68c9c25d24%EF%BC%8825Q4%E7%87%9F%E6%94%B611.83%E5%84%84%E5%85%83%EF%BC%8C%E5%AD%A3%E5%A2%9E11.79%25%E3%80%81%E5%B9%B4%E5%A2%9E27.79%25%EF%BC%89" target="_blank" rel="noreferrer">https://cmnews.com.tw/article/cmoneyaicurator-310e19db-22b4-11f1-bf01-df68c9c25d24（25Q4營收11.83億元，季增11.79%、年增27.79%）</a></li><li><strong>Win投資</strong>: <a href="https://winvest.tw/News/Detail/75248%EF%BC%882025%E5%B9%B411%E6%9C%88%E7%87%9F%E6%94%B64.48%E5%84%84%E5%85%83%EF%BC%8C%E5%B9%B4%E5%A2%9E50.38%25%EF%BC%89" target="_blank" rel="noreferrer">https://winvest.tw/News/Detail/75248（2025年11月營收4.48億元，年增50.38%）</a></li></ul>',27)])])}const E=a(l,[["render",i]]);export{F as __pageData,E as default};
